 &lt;hr /&gt;
&lt;h2 id=&#34;第1章-关键术语&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第1章-关键术语&#34;&gt;#&lt;/a&gt; 第 1 章 关键术语&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;术语&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;地址寄存器&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;指令周期&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;可编程 I/O&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;辅助寄存器&lt;/td&gt;
