&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;链式文件分配&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;散列文件&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;分区&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;连续文件分配&lt;/td&gt;
